Clear Spreadsheet Row(s).code:
// Clear cell contents in a row (or rows) by writing empty strings.
// The row(s) themselves stay in place; only the values are wiped.
batchUpdateValues({
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  valueInputOption: 'USER_ENTERED',
  data: [
    {
      // A1 range covering the row(s) to clear.
      range: 'Sheet1!A5:Z5',
      // One inner array per row, sized to the range.
      values: [Array(26).fill('')],
    },
  ],
});

Create Multiple Spreadsheet Rows.code:
// Append many rows in one call.
// Each inner array is one row; cells must line up with your columns.
appendValues({
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  range: 'Sheet1!A1:D1',
  values: $.data.records.map(r => [r.name, r.email, r.amount, r.date]),
});

Create Spreadsheet Row.code:
// Append a single row to the bottom of a sheet.
appendValues({
  // Spreadsheet ID — the long string from the sheet's URL.
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // Where to append. Sheet name + column range.
  range: 'Sheet1!A1:D1',
  // Outer array = rows, inner arrays = cells in column order.
  values: [
    [$.data.name, $.data.email, $.data.amount, $.data.date],
  ],
});

Update Spreadsheet Row.code:
// Overwrite the values of a single row.
batchUpdateValues({
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // Parse cell input like a user typed it (formulas, dates, etc.).
  valueInputOption: 'USER_ENTERED',
  data: [
    {
      range: 'Sheet1!A5:D5',
      values: [[$.data.name, $.data.email, $.data.amount, $.data.date]],
    },
  ],
});

Update Spreadsheet Row(s).code:
// Overwrite multiple ranges in one batch.
batchUpdateValues({
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  valueInputOption: 'USER_ENTERED',
  data: $.data.updates.map(u => ({
    range: u.range,
    values: [u.row],
  })),
});

Get Data Range.code:
// Read values from an A1 range. Result is on state.data as a 2d array.
getValues(
  // Spreadsheet ID.
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // A1 range — sheet name + range.
  'Sheet1!A1:D100'
);

Get Many Spreadsheet Rows (Advanced).code:
// Pull a wide range and return all rows.
getValues(
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // Open-ended range — fetches every populated row in the column span.
  'Sheet1!A2:Z'
);

Get Row by ID.code:
// Fetch a single row by its row number (1-based).
const rowId = $.data.rowId;
getValues(
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // Build an A1 range that spans only that row.
  `Sheet1!A${rowId}:Z${rowId}`
);

Lookup Spreadsheet Row.code:
// Read a range, then filter in the callback to find the matching row.
getValues(
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  'Sheet1!A1:D100',
  // Callback receives state with rows on state.data.values.
  state => {
    const [header, ...rows] = state.data.values || [];
    // Match on the second column (index 1).
    state.match = rows.find(r => r[1] === $.data.email);
    return state;
  }
);

Lookup Spreadsheet Rows (Advanced).code:
// Read a range, then filter in the callback for all matches.
getValues(
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  'Sheet1!A1:D500',
  state => {
    const [header, ...rows] = state.data.values || [];
    state.matches = rows.filter(r => r[1] === $.data.email);
    return state;
  }
);
